import {
  BoxGeometry,
  Color,
  Group,
  InstancedMesh,
  Matrix4,
  MeshStandardMaterial,
  Vector3,
} from "three";

/**
 * True voxel world for the Minecraft mode: the city as axis-aligned
 * blocks generated by `isometric_berlin.generation.build_minecraft_voxels`
 * from surveyed LoD2 footprints + measured heights, OSM water/roads and
 * the official tree points. Rendered as a handful of InstancedMeshes
 * (one box per building column / ground run / tree part) so the whole
 * world stays at a few draw calls and well below photogrammetry-tier
 * triangle counts — deliberately "eckig, klotzig, blockig".
 */
export type VoxelPayload = {
  schema_version: number;
  cell_m: number;
  classes: string[];
  grid: { cols: number; min_x_idx: number; min_z_idx: number; rows: number };
  /** Coarse ground-top heights in decimetres, row-major at stride_cells. */
  ground_height: {
    cols: number;
    rows: number;
    stride_cells: number;
    y_dm: number[];
  };
  /** rows[z_offset] = [x_start_offset, run_length, classId][] (grid offsets). */
  ground_rows: Array<Array<[number, number, number]>>;
  /** [x_idx, z_idx, y0_dm, y1_dm, classId] with ABSOLUTE cell indices. */
  buildings: Array<[number, number, number, number, number]>;
  /** [x_idx, z_idx, y0_dm, height_dm] with ABSOLUTE cell indices. */
  trees: Array<[number, number, number, number]>;
  water_top_y_m: number;
};

export const VOXEL_WORLD_FILE = "minecraft-voxels.json";
const GROUND_SLAB_M = 3;
const WATER_TOP_Y = 1.31;

// Every shade comes from MINECRAFT_PALETTE (palette.ts); small
// deterministic per-instance jitter between shades is what gives the
// classic Minecraft block-noise without any texture.
// Owner note "bessere Farben im Minecraft mode": each class now uses
// two or three CLOSE shades (gentle block-noise instead of the harsh
// checkerboard), greens follow classic plains grass/oak leaves, water is
// the clear Minecraft blue and roads read as dark slate, not void-black.
const CLASS_SHADES: Record<string, readonly number[]> = {
  asphalt: [0x40515c, 0x34443a],
  concrete: [0xd4d4b7, 0xf3efd0],
  glass: [0x72c5d2, 0xa4dfe2],
  grass: [0x74b043, 0x5d9634, 0x74b043],
  plazaBrick: [0x994a35, 0x715b4a],
  // Bridge decks over the Spree/Humboldthafen read as stone blocks.
  bridge: [0x8e9a9e, 0xa4aa91],
  sandstone: [0xe8d1ae, 0xf5e3c5],
  water: [0x3f76e4, 0x2e5aa8],
};
const FALLBACK_SHADES: readonly number[] = CLASS_SHADES.concrete;
const TRUNK_SHADES: readonly number[] = [0x704a2d];
const LEAF_SHADES: readonly number[] = [0x4c7f28, 0x5d9634];

function shadeFor(
  shades: readonly number[],
  xIdx: number,
  zIdx: number,
  salt: number,
): Color {
  const pick = Math.abs(xIdx * 31 + zIdx * 17 + salt * 7) % shades.length;
  return new Color(shades[pick]);
}

function voxelMaterial(): MeshStandardMaterial {
  return new MeshStandardMaterial({
    color: 0xffffff,
    flatShading: true,
    metalness: 0,
    roughness: 1,
  });
}

type InstanceWriter = {
  mesh: InstancedMesh;
  write: (
    center: Vector3,
    size: Vector3,
    color: Color,
  ) => void;
};

function instancedBoxes(name: string, count: number): InstanceWriter {
  const mesh = new InstancedMesh(
    new BoxGeometry(1, 1, 1),
    voxelMaterial(),
    Math.max(1, count),
  );
  mesh.name = name;
  mesh.count = 0;
  const matrix = new Matrix4();
  return {
    mesh,
    write: (center, size, color) => {
      const index = mesh.count;
      matrix.makeScale(size.x, size.y, size.z);
      matrix.setPosition(center.x, center.y, center.z);
      mesh.setMatrixAt(index, matrix);
      mesh.setColorAt(index, color);
      mesh.count = index + 1;
    },
  };
}

/**
 * Sample the payload's coarse interpolated terrain grid at grid offsets.
 */
export function groundTopSampler(
  payload: VoxelPayload,
): (xOffset: number, zOffset: number) => number {
  const heights = payload.ground_height;
  return (xOffset, zOffset) => {
    const col = Math.min(
      heights.cols - 1,
      Math.floor(xOffset / heights.stride_cells),
    );
    const row = Math.min(
      heights.rows - 1,
      Math.floor(zOffset / heights.stride_cells),
    );
    return (heights.y_dm[row * heights.cols + col] ?? 40) / 10;
  };
}

/**
 * Build the run-length ground slabs as one InstancedMesh. Shared between
 * the Minecraft voxel world and the drawn isometric city (which reuses
 * the same surveyed ground/water/road classes with its own palette).
 */
export function createGroundSlabs(
  payload: VoxelPayload,
  name: string,
  shadeMap: Record<string, readonly number[]>,
): InstancedMesh {
  const cell = payload.cell_m;
  const { min_x_idx, min_z_idx } = payload.grid;
  const worldXAbs = (xIdx: number, span = 1): number =>
    (xIdx + span / 2) * cell;
  const worldZAbs = (zIdx: number): number => (zIdx + 0.5) * cell;
  const groundTopY = groundTopSampler(payload);
  const groundRunCount = payload.ground_rows.reduce(
    (sum, row) => sum + row.length,
    0,
  );
  const ground = instancedBoxes(name, groundRunCount);
  const center = new Vector3();
  const size = new Vector3();
  payload.ground_rows.forEach((row, zOffset) => {
    for (const [xStart, run, classId] of row) {
      const className = payload.classes[classId] ?? "grass";
      const shades =
        shadeMap[className] ?? shadeMap.grass ?? FALLBACK_SHADES;
      const topY =
        className === "water"
          ? (payload.water_top_y_m ?? WATER_TOP_Y)
          : groundTopY(xStart + run / 2, zOffset);
      center.set(
        worldXAbs(min_x_idx + xStart, run),
        topY - GROUND_SLAB_M / 2,
        worldZAbs(min_z_idx + zOffset),
      );
      size.set(run * cell, GROUND_SLAB_M, cell);
      ground.write(center, size, shadeFor(shades, xStart, zOffset, run));
    }
  });
  return ground.mesh;
}

export function createMinecraftVoxelWorld(payload: VoxelPayload): Group {
  const group = new Group();
  group.name = "Minecraft voxel world (LoD2 + OSM + official tree points)";
  const cell = payload.cell_m;
  // Buildings/trees carry ABSOLUTE cell indices; ground runs are grid
  // offsets (see the payload origin note): cell (x_idx, z_idx) spans
  // world x in [x_idx*cell, x_idx*cell + cell).
  const worldXAbs = (xIdx: number, span = 1): number =>
    (xIdx + span / 2) * cell;
  const worldZAbs = (zIdx: number): number => (zIdx + 0.5) * cell;
  const center = new Vector3();
  const size = new Vector3();
  group.add(createGroundSlabs(payload, "Voxel ground runs", CLASS_SHADES));

  const buildings = instancedBoxes(
    "Voxel building columns",
    payload.buildings.length,
  );
  for (const [xIdx, zIdx, y0dm, y1dm, classId] of payload.buildings) {
    const className = payload.classes[classId] ?? "concrete";
    const shades = CLASS_SHADES[className] ?? FALLBACK_SHADES;
    const y0 = y0dm / 10;
    const height = Math.max(cell, (y1dm - y0dm) / 10);
    center.set(worldXAbs(xIdx), y0 + height / 2, worldZAbs(zIdx));
    size.set(cell, height, cell);
    buildings.write(
      center,
      size,
      shadeFor(shades, xIdx, zIdx, Math.round(height / cell)),
    );
  }
  group.add(buildings.mesh);

  const trunks = instancedBoxes("Voxel tree trunks", payload.trees.length);
  const crowns = instancedBoxes("Voxel tree crowns", payload.trees.length);
  for (const [xIdx, zIdx, y0dm, hdm] of payload.trees) {
    const y0 = y0dm / 10;
    const height = Math.max(cell, hdm / 10);
    const trunkHeight = Math.max(cell / 2, height - cell * 1.5);
    center.set(worldXAbs(xIdx), y0 + trunkHeight / 2, worldZAbs(zIdx));
    size.set(cell * 0.45, trunkHeight, cell * 0.45);
    trunks.write(center, size, shadeFor(TRUNK_SHADES, xIdx, zIdx, 1));
    const crownHeight = cell * 1.9;
    center.set(
      worldXAbs(xIdx),
      y0 + trunkHeight + crownHeight / 2,
      worldZAbs(zIdx),
    );
    size.set(cell * 2.2, crownHeight, cell * 2.2);
    crowns.write(center, size, shadeFor(LEAF_SHADES, xIdx, zIdx, 2));
  }
  group.add(trunks.mesh);
  group.add(crowns.mesh);

  for (const child of group.children) {
    if (child instanceof InstancedMesh) {
      child.instanceMatrix.needsUpdate = true;
      if (child.instanceColor) {
        child.instanceColor.needsUpdate = true;
      }
      child.frustumCulled = false;
    }
  }
  return group;
}
